import{_ as a,o as i,c as s,a2 as o}from"./chunks/framework.C90q7Ucc.js";const l="/site/codelark/assets/showcase-workbench-card.D743e9Y2.png",u=JSON.parse('{"title":"CodeLark 安装与使用指南","description":"","frontmatter":{},"headers":[],"relativePath":"guide/install-and-usage.md","filePath":"guide/install-and-usage.md","lastUpdated":1781343910000}'),d={name:"guide/install-and-usage.md"};function t(c,e,n,p,r,h){return i(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="codelark-安装与使用指南" tabindex="-1">CodeLark 安装与使用指南 <a class="header-anchor" href="#codelark-安装与使用指南" aria-label="Permalink to &quot;CodeLark 安装与使用指南&quot;">​</a></h1><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><p>CodeLark 不接管 <code>~/.codex</code>、<code>~/.claude-code</code> 或 <code>~/.claude-code-router</code> 的模型供应商配置。Codex CLI、Claude Code、CCR 或 API 登录态仍按你的本机环境自行准备；CodeLark 只保存自己的配置和桥接状态。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># export OPENAI_API_KEY=sk-xxx</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> codelark</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codelark</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span></code></pre></div><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><ul><li>本机已经可以运行 <code>codelark</code>。</li><li>本机已有可用的 Codex 登录态、Claude Code 登录态或对应 API 凭据。</li><li>本机 PATH 中已有 <code>tmux</code> 命令；如果没有，<code>codelark setup</code> 会提示确认并自动安装。Linux 使用 <code>sudo apt update &amp;&amp; sudo apt install -y tmux</code>，macOS 使用 <code>brew install tmux</code>，Windows 使用 <code>winget install --id marlocarlo.psmux --accept-package-agreements --accept-source-agreements</code> 安装 psmux（提供 <code>tmux.exe</code>）。</li><li>已创建飞书/Lark 自建应用并拿到 <code>App ID</code> / <code>App Secret</code>，或允许向导通过开放平台扫码创建机器人配置。</li><li>飞书应用已启用机器人、权限、事件订阅和长连接。详细步骤见 <a href="./platform-setup">平台配置指南</a>。</li></ul><h2 id="首次配置" tabindex="-1">首次配置 <a class="header-anchor" href="#首次配置" aria-label="Permalink to &quot;首次配置&quot;">​</a></h2><p>推荐先运行交互式向导：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codelark</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span></span></code></pre></div><p>向导会依次完成：</p><ol><li>检查 <code>tmux</code> 是否可用；缺失时先提示用户确认，再按当前系统自动安装。</li><li>选择飞书机器人配置方式。</li><li>复用 <code>~/.codelark</code> 已有配置、扫码创建新 App，或粘贴 <code>App ID</code> / <code>App Secret</code>。</li><li>按本机环境推荐默认 runtime。</li><li>选择默认工作目录。</li><li>可选设置飞书用户 open_id 白名单。</li><li>可选安装 CodeLark skills 和官方 <code>lark-doc</code> skill。本地 CodeLark skills 会先安装；官方 <code>lark-doc</code> 通过 <code>npx skills add ...</code> 单独安装，失败时不会影响本地 skills 可用。</li></ol><p>如果用户拒绝在向导中安装 tmux，向导仍会继续保存配置，但会把默认 provider 改为 SDK：<code>runtime.codex.provider = &quot;sdk&quot;</code>，并把 Claude 默认 provider 写为 <code>runtime.claude.provider = &quot;sdk&quot;</code>。之后安装 tmux 后，可以在 IM 中使用 <code>/provider tmux</code> 切回 tmux provider。</p><p>机器人配置方式有两种：</p><ul><li>使用现有 CodeLark 配置：从 <code>~/.codelark/config.toml</code> 加载已有 <code>App ID</code> / <code>App Secret</code>；首次遇到旧版 <code>config.json</code> / <code>config.env</code> 时会迁移到 TOML，不会读取用户 HOME 下的 <code>~/.lark-cli</code>。</li><li>扫码创建：通过飞书/Lark 开放平台扫码创建 App，<code>App ID</code> / <code>App Secret</code> 直接来自扫码返回结果。</li><li>手动引导：直接粘贴飞书开放平台里的 <code>App ID</code> 和 <code>App Secret</code>。</li></ul><p>保存 App 配置后，向导会基于当前 <code>~/.codelark</code> 配置初始化 CodeLark 专属 lark-cli runtime，并对这个 App 发起用户 OAuth 授权扫码。授权状态写入 <code>~/.codelark/runtime/lark-cli/</code>，不读取或导入默认 <code>~/.lark-cli</code>。</p><p>默认 runtime 推荐规则：</p><ul><li>有 <code>~/.codex</code>：推荐 Codex。</li><li>没有 Codex 但有 <code>~/.claude-code-router</code>：推荐 Claude Code Router，并使用 <code>ccr</code>。</li><li>没有前两者但有 <code>~/.claude-code</code> 或 <code>~/.claude</code>：推荐 Claude Code。</li><li>都没有：默认 Claude Code，后续可在向导或 IM 命令里切换。</li></ul><p>向导会写入：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.codelark/config.toml</span></span>
<span class="line"><span>~/.codelark/config/sessions/&lt;session-id&gt;.toml</span></span>
<span class="line"><span>~/.codelark/config/channels/&lt;channel-id&gt;.toml</span></span></code></pre></div><p><code>config.toml</code> 是全局主配置；Session 和 Channel 级持久化覆盖使用同一套 TOML shape 写入 <code>config/sessions/</code> 与 <code>config/channels/</code>。旧 <code>config.json</code> / <code>config.env</code> 只作为 v1 迁移输入，迁移成功后会归档，不再作为运行时配置来源。</p><h2 id="启动" tabindex="-1">启动 <a class="header-anchor" href="#启动" aria-label="Permalink to &quot;启动&quot;">​</a></h2><p>打开本地工作台并启动 bridge：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codelark</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span></code></pre></div><p>只启动后台 bridge：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codelark</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span></code></pre></div><p>常用本地命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codelark</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codelark</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codelark</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> url</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codelark</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">codelark</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span></span></code></pre></div><p><code>codelark run</code> 会在启动 bridge 前初始化 CodeLark 专属的 lark-cli 运行环境：</p><ul><li>从当前启用的飞书/Lark 通道生成 <code>~/.codelark/runtime/lark-cli-source/config.json</code>。</li><li>将 lark-cli 绑定到 <code>~/.codelark/runtime/lark-cli/</code>。</li><li>如果 CodeLark 专属 runtime 已有当前 App 的用户授权，则切换为 user-default；否则保持 bot-only，直到用户在 setup 中完成授权。</li><li>给 bridge 和 agent 子进程注入 <code>LARK_CHANNEL_CONFIG</code> 与 <code>LARKSUITE_CLI_CONFIG_DIR</code>。</li></ul><p>这样 bridge 内部和 agent 调用 <code>lark-cli</code> 时会使用 CodeLark 当前配置，不会误读默认用户 HOME 下的其他 lark-cli 配置。旧版 <code>codelark open</code> 仍作为兼容别名可用，但文档和脚本统一使用 <code>run</code>。</p><p>默认工作台地址：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://127.0.0.1:4781</span></span></code></pre></div><h2 id="飞书应用配置" tabindex="-1">飞书应用配置 <a class="header-anchor" href="#飞书应用配置" aria-label="Permalink to &quot;飞书应用配置&quot;">​</a></h2><p>飞书侧至少需要完成：</p><ol><li>在飞书开放平台创建自建应用，记录 <code>App ID</code> 和 <code>App Secret</code>。</li><li>启用 Bot 能力。</li><li>添加消息发送、消息读取、卡片读写、消息更新、云文档评论写入等权限。</li><li>发布版本并由管理员审批。</li><li>启动 CodeLark bridge。</li><li>在事件订阅里选择长连接。</li><li>添加 <code>im.message.receive_v1</code>、<code>drive.notice.comment_add_v1</code>、<code>im.chat.member.bot.deleted_v1</code>、<code>im.chat.disbanded_v1</code> 事件和 <code>card.action.trigger</code> 回调。</li><li>再次发布版本并审批。</li></ol><p>如果 <code>CODELARK_FEISHU_ALLOWED_USERS</code> 为空，所有能给机器人发消息的人都可以使用该 bot。需要收紧访问时，填写飞书用户 open_id 列表。</p><p>云文档评论能力除事件订阅外，还需要文档评论写入权限。缺少 <code>docs:document.comment:create</code> 或 <code>docs:document.comment:write_only</code> 时，bridge 可以收到评论事件，但无法写回评论或添加 <code>Typing</code> 表情。</p><h2 id="本地工作台" tabindex="-1">本地工作台 <a class="header-anchor" href="#本地工作台" aria-label="Permalink to &quot;本地工作台&quot;">​</a></h2><p>工作台主要用于：</p><ul><li>查看 UI 和 bridge 是否运行。</li><li>配置飞书通道实例。</li><li>测试飞书凭据和连通性。</li><li>查看本地 Codex / Claude Code 会话。</li><li>查看 CodeLark Bridge 会话和聊天绑定。</li><li>查看会话历史。</li><li>给通道设置默认目标会话。</li><li>查看日志和诊断信息。</li></ul><p><img src="`+l+`" alt="CodeLark 工作台"></p><h2 id="windows-bridge-自启动" tabindex="-1">Windows bridge 自启动 <a class="header-anchor" href="#windows-bridge-自启动" aria-label="Permalink to &quot;Windows bridge 自启动&quot;">​</a></h2><p>Windows 主机可以把 bridge 注册为开机启动任务。UI 仍然按需通过 <code>codelark</code> 或 <code>codelark run</code> 打开。</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">codelark autostart status</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">codelark autostart install</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">codelark autostart uninstall</span></span></code></pre></div><p><code>install</code> 和 <code>uninstall</code> 需要在管理员 PowerShell / 终端中执行。安装时会要求输入当前 Windows 登录密码，用于创建系统任务计划程序任务。自动启动只拉起 bridge，不会自动打开 Web 工作台；手动再次运行 <code>codelark</code> 只会补启动 UI，不会重复启动 bridge。</p><h2 id="凭据快速验证" tabindex="-1">凭据快速验证 <a class="header-anchor" href="#凭据快速验证" aria-label="Permalink to &quot;凭据快速验证&quot;">​</a></h2><p>写入配置或在 setup 中粘贴飞书凭据后，可以用下面的请求快速确认 App ID、App Secret 和站点域名是否匹配：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> POST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;\${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DOMAIN</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}/open-apis/auth/v3/tenant_access_token/internal&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{&quot;app_id&quot;:&quot;...&quot;,&quot;app_secret&quot;:&quot;...&quot;}&#39;</span></span></code></pre></div><p><code>DOMAIN</code> 飞书版通常是 <code>https://open.feishu.cn</code>，Lark 国际版通常是 <code>https://open.larksuite.com</code>。预期响应包含 <code>&quot;code&quot;:0</code>；如果不是，先检查 App ID、App Secret、站点和应用是否已创建完成。</p><h2 id="im-中的基础使用" tabindex="-1">IM 中的基础使用 <a class="header-anchor" href="#im-中的基础使用" aria-label="Permalink to &quot;IM 中的基础使用&quot;">​</a></h2><p>把机器人拉进飞书会话或直接私聊机器人后，可以使用以下最小流程：</p><ol><li>发送 <code>/status</code> 检查 bridge 和通道状态。</li><li>发送 <code>/t</code> 查看当前 runtime 最近 20 条本地会话。</li><li>在 <code>/t</code> 卡片里切换 runtime 或结果数量。</li><li>发送 <code>/t 1</code> 切换当前 IM 会话到第 1 条线程。</li><li>之后直接发送普通消息，即可继续该线程。</li></ol><p>会话 attach/detach、<code>/current</code> 和 <code>/set</code> 卡片、tmux pane 查看、agent/provider 切换以及 home/chat 配置层级，见 <a href="./session-workflows">会话、Provider 与配置工作流</a>。完整命令索引见 <a href="./../product/commands">命令体系</a>，provider 能力矩阵见 <a href="./../product/runtime-providers">运行时与提供方</a>。</p><h2 id="数据和日志" tabindex="-1">数据和日志 <a class="header-anchor" href="#数据和日志" aria-label="Permalink to &quot;数据和日志&quot;">​</a></h2><p>CodeLark 自有数据位于：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.codelark</span></span></code></pre></div><p>常见文件：</p><ul><li><code>config.toml</code>：全局主配置。</li><li><code>config/sessions/</code>：当前会话级持久化覆盖，例如工作目录、模型、provider、sandbox、reasoning、tmux 显式绑定。</li><li><code>config/channels/</code>：Channel 级持久化覆盖。</li><li><code>data/sessions.json</code>：Bridge 会话。</li><li><code>data/channel-chats.json</code>：IM chat 到 Bridge 会话的绑定。</li><li><code>data/messages/</code>：Bridge 消息缓存。</li><li><code>logs/</code>：bridge、UI 和启动器日志。</li><li><code>runtime/</code>：运行状态、PID、端口等临时状态。</li></ul><p>Codex 自己的会话数据仍由 Codex 管理，CodeLark 只读取必要索引和 JSONL：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.codex/sessions/**/*.jsonl</span></span>
<span class="line"><span>~/.codex/state_*.sqlite</span></span></code></pre></div><p>遇到启动、消息收发、权限或卡片问题时，见 <a href="./troubleshooting">排障指南</a>。</p>`,61)])])}const g=a(d,[["render",t]]);export{u as __pageData,g as default};
